head.b:skin:
/*
-----------------------------------------------
Blogger Template Style
Name:         Possil Blog
Version:      1.1.2
Author:       Possil
URL:          https://github.com/Walnut-C/Possil_blog
----------------------------------------------- */

/* Variable Definitions */
<Group description="Theme Colors" selector="body">
  <Variable name="main.color" description="Primary Theme Color" type="color" default="#2B6CB0" value="#2B6CB0"/>
  <Variable name="body.bg" description="Body Background Color" type="color" default="#F7FAFC" value="#F7FAFC"/>
  <Variable name="text.color" description="Text Color" type="color" default="#2D3748" value="#2D3748"/>
  <Variable name="link.color" description="Link Color" type="color" default="#3182CE" value="#3182CE"/>
</Group>

/* Reset & Fonts */
@import url('https://cdn.jsdelivr.net/gh/orioncactus/pretendard/dist/web/static/pretendard.css');

body {
    margin: 0;
    padding: 0;
    background-color: $(body.bg);
    color: $(text.color);
    font-family: 'Pretendard', -apple-system, BlinkMacSystemFont, system-ui, Roboto, sans-serif;
    line-height: 1.6;
}

/* Layout */
#outer-wrapper { max-width: 1000px; margin: 0 auto; padding: 0 20px; }

/* 한 줄 헤더 레이아웃 */
header { background: #FFFFFF; border-bottom: 1px solid #E2E8F0; position: sticky; top: 0; z-index: 100; }
.header-container { display: flex; justify-content: space-between; align-items: center; max-width: 1000px; margin: 0 auto; padding: 15px 20px; }
.header-inner h1 { color: $(main.color); font-size: 22px; margin: 0; letter-spacing: -0.5px; font-weight: 800; }

/* Nav (헤더 우측 배치) */
#main-nav ul { list-style: none; display: flex; padding: 0; margin: 0; }
#main-nav li a { display: block; padding: 10px 15px; color: #4A5568; font-weight: 600; text-decoration: none; transition: 0.2s; font-size: 14px; }
#main-nav li a:hover { color: $(main.color); }

/* Main Content */
#main-wrapper { padding: 30px 0; }
.post-outer { background: #FFFFFF; border-radius: 16px; padding: 30px; margin-bottom: 40px; box-shadow: 0 4px 20px rgba(0,0,0,0.04); transition: 0.3s; }
.post-outer:hover { transform: translateY(-3px); box-shadow: 0 10px 30px rgba(0,0,0,0.08); }
.post-title { font-size: 28px; line-height: 1.3; margin: 10px 0; font-weight: 800; }
.post-title a { color: #1A202C; text-decoration: none; }
.post-title a:hover { color: $(main.color); }
.post-body { font-size: 18px; color: #4A5568; margin-top: 20px; }

/* Headings in Post */
.post-body h2 { color: $(main.color); margin: 40px 0 20px; padding-bottom: 10px; border-bottom: 2px solid $(main.color); font-size: 24px; scroll-margin-top: 80px; }
.post-body h3 { color: #2D3748; margin: 30px 0 15px; font-size: 20px; font-weight: 700; scroll-margin-top: 80px; }

/* Table of Contents (Accordion) */
#possil-toc {
    background: #F8FAFC;
    border: 1px solid #E2E8F0;
    border-radius: 12px;
    margin: 30px 0;
    overflow: hidden;
}
.toc-header { 
    display: flex; 
    justify-content: space-between; 
    align-items: center; 
    padding: 15px 20px; 
    cursor: pointer; 
    background: #F1F5F9;
    transition: 0.2s;
}
.toc-header:hover { background: #E2E8F0; }
.toc-title { font-weight: 800; color: $(main.color); font-size: 16px; }
.toc-toggle-icon { 
    font-size: 12px; 
    transition: transform 0.3s; 
    color: #64748B;
}
#possil-toc.active .toc-toggle-icon { transform: rotate(180deg); }

#possil-toc ul { 
    list-style: none; 
    padding: 0 20px 20px; 
    margin: 0; 
    display: none; /* 기본 접힘 */
}
#possil-toc.active ul { display: block; }

#possil-toc li { margin-top: 10px; }
#possil-toc li a { color: #4A5568; text-decoration: none; transition: 0.2s; font-size: 15px; display: block; }
#possil-toc li a:hover { color: $(main.color); padding-left: 5px; }
#possil-toc li.toc-h3 { padding-left: 15px; font-size: 0.9em; border-left: 2px solid #E2E8F0; margin-left: 5px; }

/* Protection Elements */
#possil-credit { color: #A0AEC0; font-size: 13px; margin-top: 20px; }
#possil-credit a { color: $(main.color); font-weight: bold; }

/* Footer */
footer { padding: 60px 0; text-align: center; color: #718096; border-top: 1px solid #E2E8F0; margin-top: 40px; }

/* Anti-Tamper Lock Screen */
#tamper-lock {
    position: fixed; top: 0; left: 0; width: 100%; height: 100%;
    background: white; z-index: 999999; display: none;
    flex-direction: column; justify-content: center; align-items: center;
    text-align: center; padding: 20px;
}
#tamper-lock h1 { color: #E53E3E; font-size: 24px; margin-bottom: 10px; }

body.script:
//
    // 저작권 보호 트리거 (Anti-Tamper) 및 자동 기능 통합
    (function() {
        function checkTamper() {
            const credit = document.getElementById('possil-credit');
            const link = document.getElementById('legal-link');
            const lock = document.getElementById('tamper-lock');
            if (!credit || !link || credit.offsetParent === null || link.innerText.trim() !== 'Possil') {
                lock.style.display = 'flex';
                document.body.style.overflow = 'hidden';
            }
        }

        function initTOC() {
            const postBodies = document.querySelectorAll('.post-body');
            postBodies.forEach((postBody) => {
                const headings = postBody.querySelectorAll('h2, h3');
                if (headings.length > 0) {
                    const tocContainer = document.createElement('div');
                    tocContainer.id = 'possil-toc';
                    // 활성화 상태(열림/닫힘)를 위한 클래스 토글 로직 포함
                    let tocHtml = `
                        <div class="toc-header" onclick="this.parentElement.classList.toggle('active')">
                            <span class="toc-title">목차</span>
                            <span class="toc-toggle-icon">▼</span>
                        </div>
                        <ul>`;
                    headings.forEach((heading) => {
                        const id = heading.id || 'toc-' + Math.random().toString(36).substr(2, 7);
                        heading.id = id;
                        const levelClass = heading.tagName.toLowerCase() === 'h3' ? 'toc-h3' : 'toc-h2';
                        tocHtml += `<li class="${levelClass}"><a href="#${id}">${heading.textContent}</a></li>`;
                    });
                    tocHtml += '</ul>';
                    tocContainer.innerHTML = tocHtml;
                    postBody.insertBefore(tocContainer, postBody.firstChild);

                    // 기본적으로 열어두고 싶다면 아래 주석 해제 또는 클래스 추가
                    // tocContainer.classList.add('active');
                }
            });
        }
        // 초기화 실행
        window.addEventListener('load', function() {
            checkTamper();
            initTOC();
            const yearEl = document.getElementById('year');
            if (yearEl) yearEl.textContent = new Date().getFullYear();
        });

        // 실시간 보안 감시
        setInterval(checkTamper, 3000);
    })();
//
